import React, { useEffect, useRef, useState } from "react";
import io from "socket.io-client";
import axios from "axios";
import EmojiPicker from "emoji-picker-react";
import "./App.css";

// ---- CONFIG ----
const SERVER_URL = process.env.REACT_APP_SERVER_URL || "http://localhost:3001";

// Single socket instance (no duplicates)
const socket = io(SERVER_URL, { transports: ["websocket"] });

function formatTimestamp(dateString) {
  const d = new Date(dateString);
  return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
}

const SingleCheck = () => (
  <svg xmlns="http://www.w3.org/2000/svg" className="tick-icon single" viewBox="0 0 24 24">
    <path d="M4 12l5 5L20 7" fill="none" stroke="gray" strokeWidth="2" />
  </svg>
);

const DoubleCheck = () => (
  <svg xmlns="http://www.w3.org/2000/svg" className="tick-icon double" viewBox="0 0 24 24">
    <path d="M3 12l5 5L20 5" fill="none" stroke="#00e5ff" strokeWidth="2" />
    <path d="M9 12l5 5L23 5" fill="none" stroke="#00e5ff" strokeWidth="2" />
  </svg>
);

export default function App() {
  // ---- Auth / Session ----
  const [username, setUsername] = useState(null);
  const [token, setToken] = useState(null);
  const [mode, setMode] = useState("login");
  const [form, setForm] = useState({ username: "", email: "", password: "" });

  // ---- Chat state ----
  const [messages, setMessages] = useState([]);
  const [text, setText] = useState("");
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [typingUser, setTypingUser] = useState(null);

  // ---- UI state ----
  const [darkMode, setDarkMode] = useState(false);
  const [showNewMessages, setShowNewMessages] = useState(false);
  const [fadeOut, setFadeOut] = useState(false);
  const [newMsgCount, setNewMsgCount] = useState(0);
  const [showEmoji, setShowEmoji] = useState(false);

  // ---- Refs ----
  const messagesEndRef = useRef(null);
  const typingTimeoutRef = useRef(null);
  const hideTimerRef = useRef(null);

  // Utility: get messages container
  const getMessagesDiv = () => messagesEndRef.current?.parentNode;

  // Smooth, reliable scroll
  const scrollToBottom = (behavior = "smooth") => {
    const el = getMessagesDiv();
    if (!el) return;
    el.scrollTo({ top: el.scrollHeight, behavior });
  };

  const isNearBottom = () => {
    const el = getMessagesDiv();
    if (!el) return true;
    const { scrollTop, clientHeight, scrollHeight } = el;
    return scrollHeight - scrollTop <= clientHeight + 50;
  };

  // ---- Boot stored session + theme, and join socket room ----
  useEffect(() => {
    const u = localStorage.getItem("chatUser");
    const t = localStorage.getItem("chatToken");
    const theme = localStorage.getItem("darkMode");
    if (u && t) {
      setUsername(u);
      setToken(t);
      socket.emit("joinRoom", { username: u }); // server expects { username } for "global" room
    }
    if (theme === "true") {
      setDarkMode(true);
      document.body.classList.add("dark");
    }
  }, []);

  // ---- Auth handlers ----
  const handleAuth = async (e) => {
    e.preventDefault();
    try {
      const url = `${SERVER_URL}/${mode}`;
      const res = await axios.post(url, form);
      setUsername(res.data.username);
      setToken(res.data.token);
      localStorage.setItem("chatUser", res.data.username);
      localStorage.setItem("chatToken", res.data.token);
      socket.emit("joinRoom", { username: res.data.username });
    } catch (err) {
      alert(err.response?.data?.error || "Auth failed");
    }
  };

  const handleLogout = () => {
    setUsername(null);
    setToken(null);
    localStorage.removeItem("chatUser");
    localStorage.removeItem("chatToken");
  };

  const toggleDarkMode = () => {
    const newMode = !darkMode;
    setDarkMode(newMode);
    document.body.classList.toggle("dark", newMode);
    localStorage.setItem("darkMode", newMode);
  };

  // ---- Initial message load (after auth) ----
  useEffect(() => {
    if (!username) return;

    (async () => {
      try {
        const res = await axios.get(`${SERVER_URL}/messages`); // server serves "global" room
        setMessages(res.data || []);
        // Mark as read immediately if you land at bottom:
        setTimeout(() => {
          scrollToBottom("auto");
          socket.emit("markAsRead", { username }); // server expects { username }
        }, 30);
      } catch (err) {
        console.error("Failed to fetch messages:", err);
      }
    })();
  }, [username]);

  // ---- Socket listeners ----
  useEffect(() => {
    const receiveHandler = (message) => {
      setMessages((prev) => [...prev, message]);

      // Sender always autoscroll
      if (message.username === username) {
        setTimeout(() => scrollToBottom(), 40);
        return;
      }

      // For recipients: show pill if not near bottom, else scroll
      if (!isNearBottom()) {
        setNewMsgCount((c) => c + 1);
        setShowNewMessages(true);
        setFadeOut(false);
      } else {
        setTimeout(() => scrollToBottom(), 40);
      }
    };

    const readHandler = (updatedMessages) => {
      // Replace readBy on any known message with server's truth
      setMessages((prev) => {
        const map = new Map(updatedMessages.map((m) => [m._id, m]));
        return prev.map((m) => (map.has(m._id) ? { ...m, readBy: [...map.get(m._id).readBy] } : m));
      });
    };

    const onlineHandler = (users) => setOnlineUsers(users || []);
    const typingHandler = (user) => setTypingUser(user);
    const stopTypingHandler = () => setTypingUser(null);

    socket.on("receiveMessage", receiveHandler);
    socket.on("messageRead", readHandler);
    socket.on("onlineUsers", onlineHandler);
    socket.on("typing", typingHandler);
    socket.on("stopTyping", stopTypingHandler);

    return () => {
      socket.off("receiveMessage", receiveHandler);
      socket.off("messageRead", readHandler);
      socket.off("onlineUsers", onlineHandler);
      socket.off("typing", typingHandler);
      socket.off("stopTyping", stopTypingHandler);
    };
  }, [username]);

  // ---- Keep bottom sticky when appropriate ----
  useEffect(() => {
    // If last message is mine, always scroll
    const last = messages[messages.length - 1];
    if (last?.username === username) {
      scrollToBottom();
      return;
    }

    // If user is already near bottom, follow new messages
    if (isNearBottom()) scrollToBottom();
  }, [messages]); // eslint-disable-line

  // ---- New message pill auto-hide timer ----
  useEffect(() => {
    if (!showNewMessages) return;
    if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
    hideTimerRef.current = setTimeout(() => {
      setFadeOut(true);
      setTimeout(() => {
        setShowNewMessages(false);
        setNewMsgCount(0);
      }, 500);
    }, 5000);
    return () => {
      if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
    };
  }, [showNewMessages]);

  // ---- Scroll handler (mark as read when you hit bottom) ----
  const handleScroll = (e) => {
    const el = e.target;
    const near = el.scrollHeight - el.scrollTop <= el.clientHeight + 50;
    if (near) {
      setShowNewMessages(false);
      setNewMsgCount(0);
      if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
      if (username) socket.emit("markAsRead", { username }); // server updates readBy and emits "messageRead"
    }
  };

  // ---- Typing handlers ----
  const handleTyping = (e) => {
    const v = e.target.value;
    setText(v);
    if (!username) return;
    socket.emit("typing", username); // server expects username string
    if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    typingTimeoutRef.current = setTimeout(() => socket.emit("stopTyping"), 900);
  };

  // ---- Send message ----
  const sendMessage = (e) => {
    e.preventDefault();
    const trimmed = text.trim();
    if (!trimmed) return;
    socket.emit("sendMessage", { username, text: trimmed }); // server saves & broadcasts
    setText("");
    setShowEmoji(false);
    socket.emit("stopTyping");
    setTimeout(() => scrollToBottom(), 35);
  };

  // ---- Emoji picker ----
  const onEmojiClick = (emojiData) => {
    // emojiData.emoji contains the unicode emoji; append to text
    setText((t) => t + (emojiData?.emoji || ""));
  };

  // ---- Auth screen ----
  if (!username) {
    return (
      <div className="app">
        <div className="login">
          <h2>{mode === "login" ? "Login" : "Signup"}</h2>
          <form onSubmit={handleAuth}>
            <input
              type="text"
              placeholder="Username"
              value={form.username}
              onChange={(e) => setForm({ ...form, username: e.target.value })}
            />
            {mode === "signup" && (
              <input
                type="email"
                placeholder="Email"
                value={form.email || ""}
                onChange={(e) => setForm({ ...form, email: e.target.value })}
              />
            )}
            <input
              type="password"
              placeholder="Password"
              value={form.password}
              onChange={(e) => setForm({ ...form, password: e.target.value })}
            />
            <button type="submit">{mode === "login" ? "Login" : "Signup"}</button>
          </form>
          <p>
            {mode === "login" ? "Don't have an account?" : "Already registered?"}{" "}
            <button className="link" onClick={() => setMode(mode === "login" ? "signup" : "login")}>
              {mode === "login" ? "Signup" : "Login"}
            </button>
          </p>
        </div>
      </div>
    );
  }

  // ---- Chat screen ----
  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2>Welcome, {username} 👋</h2>
        <div>
          <button className="toggle-dark" onClick={toggleDarkMode}>
            {darkMode ? "☀️ Light" : "🌙 Dark"}
          </button>
          <button className="logout" onClick={handleLogout}>Logout</button>
        </div>
      </div>

      <div className="chat-main">
        <aside className="sidebar">
          <h4>Online Users</h4>
          <ul>{onlineUsers.map((u, i) => <li key={i}>{u}</li>)}</ul>
        </aside>

        <section className="messages-area">
          <div className="messages" onScroll={handleScroll}>
            {messages.map((m, i) => {
              const mine = m.username === username;
              const readers = (m.readBy || []).filter((u) => u !== m.username);
              return (
                <div key={m._id || i} className={`message ${mine ? "me" : "other"}`}>
                  <div className="text">
                    {!mine && <strong>{m.username}: </strong>}
                    {m.text}
                    <span className="timestamp">
                      {formatTimestamp(m.createdAt)}
                      {mine && (readers.length > 0 ? <DoubleCheck /> : <SingleCheck />)}
                    </span>
                  </div>
                </div>
              );
            })}
            <div ref={messagesEndRef} />
          </div>

          {typingUser && <div className="typing">{typingUser} is typing...</div>}

          {showNewMessages && (
            <div
              className={`newMessages ${fadeOut ? "hide" : ""}`}
              onClick={() => {
                scrollToBottom();
                setShowNewMessages(false);
                setNewMsgCount(0);
                if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
              }}
            >
              {newMsgCount > 1 ? `${newMsgCount} New Messages ↓` : "New Message ↓"}
            </div>
          )}

          <form className="composer" onSubmit={sendMessage}>
            <div className="emoji-wrap">
              <button
                type="button"
                className="emoji-btn"
                onClick={() => setShowEmoji((s) => !s)}
                aria-label="Toggle emoji picker"
                title="Emoji"
              >
                😊
              </button>
              {showEmoji && (
                <div className="emoji-popover" onMouseDown={(e) => e.preventDefault()}>
                  <EmojiPicker onEmojiClick={(_, data) => onEmojiClick(data || _)} />
                </div>
              )}
            </div>

            <textarea
              value={text}
              onChange={handleTyping}
              placeholder="Type a message…"
            />
            <button type="submit">Send</button>
          </form>
        </section>
      </div>
    </div>
  );
}
